scripts.build:cli:
esbuild src/cli/index.ts --bundle --platform=node --format=esm --outfile=dist/cli/index.js --external:chokidar --external:glob --external:commander --external:chalk --external:autoprefixer --external:postcss --external:clean-css && chmod +x dist/cli/index.js && echo '#!/usr/bin/env node
const { spawn } = require("child_process");
const path = require("path");
const cliPath = path.join(__dirname, "index.js");
const args = process.argv.slice(2);
const child = spawn("node", [cliPath, ...args], { stdio: "inherit", shell: false });
child.on("close", (code) => process.exit(code));' > dist/cli/cli.cjs && chmod +x dist/cli/cli.cjs
